def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 3:
            priority_score = 3000 + (ratio - 3) * 250
        elif 2 < ratio <= 3:
            priority_score = 800 + (ratio - 2) * 150
        elif 1 < ratio <= 2:
            priority_score = 500 + (ratio - 1) * 100
        elif ratio == 1:
            priority_score = 200
        else:
            score = 0.0
            for j in range(1, 15):
                diff = capacity - item
                base = capacity if capacity != 0 else 1
                temp = (diff ** j) / (base ** j)
                if temp < 0.03:
                    score += temp * 120
                elif 0.03 <= temp < 0.1:
                    score += temp * 30 / j
                elif 0.1 <= temp < 0.25:
                    score += temp * 10 / (j**1.5)
                else:
                    score += temp * 3 / (j**2)
            if score < 0.04:
                priority_score = score * 25
            elif 0.04 <= score < 0.2:
                priority_score = 1 / (score + 0.4) + 5 * (item / capacity)
            else:
                adjustment = 0
                for k in range(1, 6):
                    adjustment += ((item / (capacity + k)) ** k) * 15 / (k + 1)
                penalty = 0
                for m in range(1, 4):
                    penalty += ((capacity - item)**m) / ((item + 1)**(m+1)) * 10 / m
                if penalty > 5:
                    penalty = 5
                priority_score = 1 / (score + 0.8) + adjustment - penalty
        if capacity - item < 0.15 * capacity:
            priority_score += 0.15 * (capacity - item) ** 2 / max(1, capacity)
        if item > 0.85 * capacity:
            priority_score *= 0.85
        if i % 3 == 0:
            priority_score += 2 / (capacity + 2) + (item % (capacity + 1)) / (capacity + 5)
        elif i % 3 == 1:
            priority_score -= 1 / (capacity + 3) + ((capacity - item) % 2) / (capacity + 6)
        else:
            priority_score += 0.5 * (np.sin(item / (capacity + 1)) + np.cos(capacity / (item + 1)))
        priorities[i] = priority_score
    return priorities
